// Normaliza el mensaje independientemente del canal de origen
const body = $input.first().json;

let canal = 'web';
let mensaje = '';
let usuarioId = '';
let nombreUsuario = 'Usuario';
let chatId = '';

// Detectar canal
if (body.message && body.message.text) {
  // Telegram
  canal = 'telegram';
  mensaje = body.message.text;
  usuarioId = String(body.message.from.id);
  nombreUsuario = body.message.from.first_name || 'Usuario';
  chatId = String(body.message.chat.id);
} else if (body.Body && body.From) {
  // WhatsApp (Twilio)
  canal = 'whatsapp';
  mensaje = body.Body;
  usuarioId = body.From;
  nombreUsuario = body.ProfileName || 'Usuario';
  chatId = body.From;
} else if (body.message && body.userId) {
  // Web
  canal = 'web';
  mensaje = body.message;
  usuarioId = body.userId || 'web-user';
  nombreUsuario = body.userName || 'Usuario';
  chatId = body.userId;
}

return [{
  json: {
    canal,
    mensaje,
    usuarioId,
    nombreUsuario,
    chatId,
    timestamp: new Date().toISOString()
  }
}];

const response = $input.first().json;
const clasificacion = response.content[0].text.trim().toUpperCase();
const prevData = $('🔄 Normalizador de Canal').first().json;

const categorias = ['VENTAS', 'SOPORTE', 'FACTURACION', 'ESCALAMIENTO', 'GENERAL'];
const categoria = categorias.includes(clasificacion) ? clasificacion : 'GENERAL';

return [{
  json: {
    ...prevData,
    categoria
  }
}];

const prevData = $input.first().json;

// Simula notificación al equipo humano (en producción: enviar a Slack/email)
console.log(`ESCALAMIENTO REQUERIDO - Usuario: ${prevData.usuarioId} - Canal: ${prevData.canal}`);

return [{
