    ...prevData,
    respuesta: `Entiendo que necesitas atención especializada, ${prevData.nombreUsuario}. 🙏\n\nHe notificado a nuestro equipo de soporte humano y te contactarán en menos de 30 minutos por este mismo canal.\n\nMientras tanto, si es urgente puedes escribir directamente a soporte@empresa.com o llamar al +52 55 1234 5678 (9am–7pm CDMX).`,
    agente: 'ESCALAMIENTO',
    escalado: true
  }
}];

