// Unifica la respuesta de todos los agentes en un formato estándar
const input = $input.first().json;
let respuesta = '';
let agente = '';

// Si ya tiene respuesta (escalamiento), usarla directamente
if (input.respuesta) {
  respuesta = input.respuesta;
  agente = input.agente || 'ESCALAMIENTO';
} else if (input.content && input.content[0]) {
  // Respuesta de Claude API
  respuesta = input.content[0].text;
  agente = 'IA';
} else {
  respuesta = 'Lo siento, tuve un problema procesando tu consulta. Por favor intenta de nuevo.';
  agente = 'ERROR';
}

// Recuperar datos del contexto
const contextNode = $('🔄 Normalizador de Canal');
const context = contextNode.first().json;

return [{
  json: {
    canal: context.canal,
    chatId: context.chatId,
    usuarioId: context.usuarioId,
    nombreUsuario: context.nombreUsuario,
    mensaje_original: context.mensaje,
    respuesta,
    agente,
    timestamp: new Date().toISOString()
  }
}];
